package vn.diabetes.service;
import static org.junit.jupiter.api.Assertions.*;import java.time.LocalDate;import java.util.concurrent.atomic.AtomicBoolean;import org.junit.jupiter.api.Test;
class PatientRegistrationServiceTest {
 @Test void registersValidatedPatient(){AtomicBoolean called=new AtomicBoolean();PatientRegistrationGateway gateway=(u,p,n,ph,e,d,g,a,i,c)->{called.set(true);assertTrue(p.length()>=8);return 42;};PatientRegistrationService service=new PatientRegistrationService(gateway);var result=service.register(new PatientRegistrationService.Command("patient_01","Patient@123","Patient@123","Nguyễn Văn An","0985000001","an@example.com","1990-05-20","Nam","Hà Nội","HN479000000001",null));assertEquals(42,result.patientId());assertTrue(called.get());}
 @Test void rejectsMismatchedPasswordBeforeDatabase(){PatientRegistrationService service=new PatientRegistrationService((u,p,n,ph,e,d,g,a,i,c)->fail("gateway must not be called"));IllegalArgumentException ex=assertThrows(IllegalArgumentException.class,()->service.register(new PatientRegistrationService.Command("patient_01","Patient@123","Other@123","Nguyễn Văn An","0985000001","an@example.com","1990-05-20","Nam","Hà Nội","",null)));assertTrue(ex.getMessage().contains("không khớp"));}
 @Test void staffRegistrationMayOmitEmailButRequiresCompleteIdentity(){PatientRegistrationService service=new PatientRegistrationService((u,p,n,ph,e,d,g,a,i,c)->7);var result=service.register(new PatientRegistrationService.Command("patient_02","Patient@123",null,"Trần Thị Bình","0985000002","","1995-08-16","Nữ","Hà Nội","",10));assertEquals(7,result.patientId());assertThrows(IllegalArgumentException.class,()->service.register(new PatientRegistrationService.Command("patient_03","Patient@123",null,"Lê Văn C","0985000003","","","Nam","","",10)));}
}
